@cat_WCC_AWARDS_PROCESSING int,@cat_WCC_NY_FORMS int,@cat_WCC_FOLLOW_UP int,@cat_WCC_OUT_OF_STATE int,@cat_WCC_PA_FORMS int,@cat_WCC_DEPENDENCY int,
@cat_WCC_FIRST_NOTICE_OF_LOSS int,@cat_WCC_BLANK_LETTER_TEMPLATES int;

Select @cat_wcc_legal=  CategoryId from [dbo].[Category] where CategoryName='WCC_LEGAL'
Select @cat_WCC_ADJUSTER=  CategoryId from [dbo].[Category] where CategoryName='WCC_ADJUSTER'
Select @cat_WCC_MEDICAL_UTILIZATION=  CategoryId from [dbo].[Category] where CategoryName='WCC_MEDICAL_UTILIZATION'
Select @cat_WCC_SUBROGATION=  CategoryId from [dbo].[Category] where CategoryName='WCC_SUBROGATION'
Select @cat_WCC_AWARDS_PROCESSING=  CategoryId from [dbo].[Category] where CategoryName='WCC_AWARDS_PROCESSING'
Select @cat_WCC_NY_FORMS=  CategoryId from [dbo].[Category] where CategoryName='WCC_NY_FORMS'
Select @cat_WCC_FOLLOW_UP=  CategoryId from [dbo].[Category] where CategoryName='WCC_FOLLOW_UP'
Select @cat_WCC_OUT_OF_STATE=  CategoryId from [dbo].[Category] where CategoryName='WCC_OUT_OF_STATE'
Select @cat_WCC_PA_FORMS=  CategoryId from [dbo].[Category] where CategoryName='WCC_PA_FORMS'
Select @cat_WCC_DEPENDENCY=  CategoryId from [dbo].[Category] where CategoryName='WCC_DEPENDENCY'
Select @cat_WCC_FIRST_NOTICE_OF_LOSS=  CategoryId from [dbo].[Category] where CategoryName='WCC_FIRST_NOTICE_OF_LOSS'
Select @cat_WCC_BLANK_LETTER_TEMPLATES=  CategoryId from [dbo].[Category] where CategoryName='WCC_BLANK_LETTER_TEMPLATES'



declare @Perminssions varchar(200);
IF @@SERVERNAME = 'SQLP09AGBUS9,54931'
set @Perminssions='Inspire_ACE_Prod,Inspire_CNSLT_GC,Inspire_WC_Claims,Inspire_CNSLT_WCC'
else
set @Perminssions = 'Inspire_ACE_NonProd,Inspire_Dev_Users,Inspire_Developers,Inspire_CNSLT_GC,Inspire_WC_Claims,Inspire_CNSLT_WCC'

if not exists (select * from LOBCategory where LOBId = @LobIdWCC)
INSERT INTO [dbo].[LOBCategory]
	  ([LOBId]
      ,[CategoryId]
      ,[CategoryOrder]
	  ,[CategoryGroups]
	  ,[EffectiveDate]
	  ,[ExpirationDate]
      ,[CreatedBy]
      ,[CreatedDateTime]
      ,[UpdatedBy]
      ,[UpdatedDateTime])

  VALUES
	(@LobIdWCC,@cat_wcc_legal,10,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_ADJUSTER,20,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_MEDICAL_UTILIZATION,30,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_SUBROGATION,40,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_AWARDS_PROCESSING,50,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_FOLLOW_UP,60,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_OUT_OF_STATE,70,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_PA_FORMS,80,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_DEPENDENCY,90,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_FIRST_NOTICE_OF_LOSS,100,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_BLANK_LETTER_TEMPLATES,110,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null),
	(@LobIdWCC,@cat_WCC_NY_FORMS,120,@Perminssions,DATEADD(YEAR,-1,GETDATE()),DATEADD(YEAR,90,GETDATE()), SUSER_SNAME(),GETDATE(),null,null)
GO

